package main

import (
	"errors"
	"fmt"
)

// splitAndSum divides nums at pivot and returns sums of each half.
// Returns an error if pivot is out of bounds.
func splitAndSum(nums []int, pivot int) [[SLOT return_sig]] {
	if pivot < 0 || pivot >= len(nums) {
		return 0, 0, [[SLOT err_construct]]("pivot out of bounds")
	}
	leftSum := 0
	for i := 0; i < pivot; i++ {
		leftSum += nums[i]
	}
	rightSum := 0
	for i := pivot; i < len(nums); i++ {
		rightSum += nums[i]
	}
	return leftSum, rightSum, [[SLOT nil_kw]]
}

func main() {
	left, right, err := splitAndSum([]int{1, 2, 3, 4, 5}, 2)
	if [[SLOT err_check]] {
		fmt.Println("Error:", err)
	} else {
		fmt.Println("Left:", left, "Right:", right)
	}
}
